import React, { useEffect, useState, useRef } from 'react';

// ─── DATA ────────────────────────────────────────────────────────────────────

const SLIDES = [
  {
    id: 1,
    headline: '5 + 1 MEALS',
    sub: 'Save as much as 20%',
    savings: 'Save as much as ₱298',
    bg: '#c8102e',
    accent: '#fff',
  },
  {
    id: 2,
    headline: 'HANDCRAFTED TASTE & FLAVOR',
    sub: 'Korean Fried Chicken Done Right',
    savings: 'Now available for delivery',
    bg: '#111',
    accent: '#c8102e',
  },
  {
    id: 3,
    headline: 'BOLD. CRISPY. SAUCY.',
    sub: 'Experience the BonChon difference',
    savings: 'Order online today',
    bg: '#8b0000',
    accent: '#fff',
  },
];

const CATEGORIES = [
  { name: 'Korean Feast', count: '4 Menu', emoji: '🍗' },
  { name: 'Chicken & Seafood Rack', count: '2 Menu', emoji: '🦐' },
  { name: 'BonChon-to-Share', count: '5 Menu', emoji: '📦' },
  { name: 'Rice Bowls', count: '6 Menu', emoji: '🍚' },
];

const FEATURES = [
  { icon: '✦', title: 'Handcrafted Daily', desc: 'Every piece of chicken is hand-brushed with our signature sauces twice for maximum flavor.' },
  { icon: '✦', title: 'Korean Heritage', desc: 'Rooted in Korean culinary tradition, perfected for every palate worldwide.' },
  { icon: '✦', title: 'Double-Fried Crunch', desc: 'Our double-frying technique creates an irresistibly light, crispy crust every time.' },
  { icon: '✦', title: 'Global Expansion', desc: 'From Seoul to Manila — BonChon brings authentic Korean comfort food to the world.' },
];

// ─── COMPONENTS ──────────────────────────────────────────────────────────────

const FoodPlaceholder = ({ label, style, className }) => (
  <div className={`food-placeholder ${className || ''}`} style={style}>
    <div className="food-placeholder-inner">
      <span className="food-icon">🍗</span>
      <span className="food-label">{label}</span>
    </div>
  </div>
);

// ─── HOME ────────────────────────────────────────────────────────────────────

const Home = ({ setCurrentPage }) => {
  const [activeSlide, setActiveSlide] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [email, setEmail] = useState('');
  const timerRef = useRef(null);

  const goTo = (idx) => {
    if (animating || idx === activeSlide) return;
    setAnimating(true);
    setTimeout(() => {
      setActiveSlide(idx);
      setAnimating(false);
    }, 350);
  };

  useEffect(() => {
    timerRef.current = setInterval(() => {
      setActiveSlide(prev => (prev + 1) % SLIDES.length);
    }, 5000);
    return () => clearInterval(timerRef.current);
  }, []);

  const slide = SLIDES[activeSlide];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Barlow:ital,wght@0,400;0,600;0,700;1,400&display=swap');

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        :root {
          --red: #c8102e;
          --red-dark: #8b0000;
          --black: #111;
          --white: #fff;
          --off-white: #f9f6f1;
          --gray: #888;
          --font-display: 'Bebas Neue', sans-serif;
          --font-body: 'Barlow', sans-serif;
          --radius: 4px;
          --transition: 0.35s cubic-bezier(0.4,0,0.2,1);
        }

        .home { font-family: var(--font-body); color: var(--black); background: var(--white); overflow-x: hidden; }

        /* ── HERO SLIDESHOW ───────────────────────────────────────── */
        .hero {
          position: relative;
          height: 90vh;
          min-height: 520px;
          overflow: hidden;
        }

        .hero-slide {
          position: absolute; inset: 0;
          display: flex; align-items: center;
          padding: 0 7vw;
          transition: opacity var(--transition), transform var(--transition);
          opacity: 0; transform: translateX(40px);
        }
        .hero-slide.active { opacity: 1; transform: translateX(0); }
        .hero-slide.exit   { opacity: 0; transform: translateX(-40px); }

        .hero-bg {
          position: absolute; inset: 0;
          transition: background var(--transition);
        }
        .hero-bg-pattern {
          position: absolute; inset: 0;
          background-image: radial-gradient(circle at 20% 50%, rgba(255,255,255,0.06) 0%, transparent 60%),
                            repeating-linear-gradient(45deg, transparent, transparent 40px, rgba(0,0,0,0.03) 40px, rgba(0,0,0,0.03) 41px);
        }

        .hero-text-wrap {
          position: relative; z-index: 2;
          max-width: 600px;
        }

        .hero-eyebrow {
          display: inline-flex; align-items: center; gap: 10px;
          font-family: var(--font-body); font-size: 13px; font-weight: 700;
          letter-spacing: 0.15em; text-transform: uppercase;
          color: rgba(255,255,255,0.7);
          margin-bottom: 20px;
        }
        .hero-eyebrow::before {
